import React, { useState } from 'react';
import QuizSetup from './QuizSetup';
import './QuizBoard.css';
import { motion, AnimatePresence } from 'framer-motion';
import Lottie from 'lottie-react';
import confettiAnim from '../assets/confetti-lottie.json'; // fallback to emoji if not present

// Demo avatars for role
const avatars = {
  teacher: '🧑‍🏫',
  mentor: '🧑‍💼',
  student: '🧑‍🎓',
};

// Demo color themes for role
const themes = {
  teacher: { bg: '#e0e7ff', accent: '#6366f1' },
  mentor: { bg: '#f0fdf4', accent: '#22c55e' },
  student: { bg: '#fef9c3', accent: '#f59e42' },
};

// Real: fetch quiz data from FastAPI backend
async function fetchQuiz({ prompt, role, difficulty, num_questions, explanations }) {
  const apiUrl = process.env.REACT_APP_API_URL || 'http://localhost:8000';
  const res = await fetch(`${apiUrl}/api/generate-quiz`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ prompt, role, difficulty, num_questions, explanations })
  });
  if (!res.ok) {
    throw new Error(`Failed to generate quiz: ${res.status}`);
  }
  const data = await res.json();
  return data;
}

async function submitAnswers({ questions, user_answers }) {
  const apiUrl = process.env.REACT_APP_API_URL || 'http://localhost:8000';
  const res = await fetch(`${apiUrl}/api/submit-answers`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ questions, user_answers })
  });
  if (!res.ok) {
    throw new Error(`Failed to submit answers: ${res.status}`);
  }
  return await res.json();
} 

function QuizBoard({ quiz, onRestart }) {
  const [current, setCurrent] = useState(0);
  const [selected, setSelected] = useState(null);
  const [answers, setAnswers] = useState([]);
  const [results, setResults] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const [showToast, setShowToast] = useState(false);
  const [timer, setTimer] = useState(15);
  const [feedback, setFeedback] = useState(null); // 'correct' | 'wrong' | null
  const [animating, setAnimating] = useState(false);
  const theme = themes[quiz.role] || themes.teacher;
  const avatar = avatars[quiz.role] || avatars.teacher;
  const q = quiz.questions[current];
  const encouragements = [
    "Let's go!",
    "Keep it up!",
    "You're doing great!",
    "Halfway there!",
    "Almost done!"
  ];
  const encouragement = encouragements[Math.floor((current/quiz.questions.length)*encouragements.length)] || '';

  // For confetti
  const getScorePct = () => results ? (results.correct / results.total) : 0;
  const showConfetti = results && getScorePct() >= 0.7;
  const motivational = results ? (
    getScorePct() === 1 ? "🏆 Perfect! You're a quiz master!" :
    getScorePct() >= 0.8 ? "🎉 Great job!" :
    getScorePct() >= 0.6 ? "👏 Good effort!" :
    "💡 Try again for a better score!"
  ) : null;

  // Timer effect
  React.useEffect(() => {
    if (results) return;
    if (timer === 0) {
      handleTimeout();
      return;
    }
    const interval = setInterval(() => setTimer(t => t-1), 1000);
    return () => clearInterval(interval);
  }, [timer, results]);

  React.useEffect(() => {
    setTimer(15);
    setSelected(null);
    setFeedback(null);
    setAnimating(false);
  }, [current]);

  const handleTimeout = () => {
    setFeedback('timeout');
    setAnimating(true);
    setTimeout(() => {
      handleNext(true);
    }, 1100);
  };

  const handleOption = idx => {
    setSelected(idx);
    if (q.answer === idx || (Array.isArray(q.answer) && Array.isArray(idx) && idx.sort().join() === q.answer.sort().join())) {
      setFeedback('correct');
    } else {
      setFeedback('wrong');
    }
    setAnimating(true);
    setTimeout(() => {
      handleNext();
    }, 1200);
  };

  const handleNext = async (timeout=false) => {
    const newAnswers = [...answers, selected];
    setAnswers(newAnswers);
    setSelected(null);
    if (current < quiz.questions.length - 1) {
      setCurrent(current + 1);
    } else {
      setLoading(true);
      setError(null);
      try {
        const res = await submitAnswers({ questions: quiz.questions, user_answers: newAnswers });
        setResults(res);
      } catch (err) {
        setError(err.message || 'Failed to submit answers.');
        setShowToast(true);
        setTimeout(() => setShowToast(false), 3000);
      } finally {
        setLoading(false);
      }
    }
  };

  if (loading) return <div className="spinner-container"><div className="spinner"></div><div style={{marginTop:'1rem'}}>Scoring quiz...</div></div>;
  if (error && showToast) return <div className="toast-error">{error}</div>;
  if (results) {
    return (
      <motion.div className="quiz-results" style={{ background: theme.bg, borderRadius: '24px', padding: '2rem', margin: '2rem auto', maxWidth: 500 }}
        initial={{opacity:0, y:30}} animate={{opacity:1, y:0}} transition={{duration:0.7}}>
        <div style={{display:'flex', alignItems:'center', gap:16}}>
          <span style={{fontSize:'2.5rem'}}>{avatar}</span>
          <h2 style={{ color: theme.accent, margin:0 }}>Quiz Results</h2>
        </div>
        {showConfetti && <Lottie animationData={confettiAnim} loop={false} autoplay style={{width:120,margin:'0 auto'}} />}
        <div style={{ margin: '1rem 0', fontWeight: 600, fontSize:'1.2rem' }}>
          Score: {results.correct} / {results.total}
        </div>
        <div style={{fontWeight:600, fontSize:'1.1rem', color:'#23254c', marginBottom:12}}>{motivational}</div>
        <ul style={{ listStyle: 'none', padding: 0 }}>
          {results.results.map((r, idx) => (
            <motion.li key={idx} style={{ marginBottom: '1.5rem', background: '#fff', borderRadius: 12, padding: '1rem', boxShadow: '0 2px 8px #eee' }}
              initial={{opacity:0, y:30}} animate={{opacity:1, y:0}} transition={{duration:0.5, delay:idx*0.1}}>
              <div style={{ fontWeight: 600 }}>{idx + 1}. {r.question}</div>
              <div>Your answer: <span style={{ color: r.correct ? 'green' : 'red', fontWeight: 600 }}>{Array.isArray(r.user_answer) ? r.user_answer.map(i => quiz.questions[idx].options[i]).join(', ') : quiz.questions[idx].options[r.user_answer]}</span></div>
              {!r.correct && (
                <div>Correct answer: <span style={{ color: 'green', fontWeight: 600 }}>{Array.isArray(r.correct_answer) ? r.correct_answer.map(i => quiz.questions[idx].options[i]).join(', ') : quiz.questions[idx].options[r.correct_answer]}</span></div>
              )}
              {r.explanation && (
                <div style={{ fontStyle: 'italic', marginTop: 4, color: '#555' }}>Explanation: {r.explanation}</div>
              )}
            </motion.li>
          ))}
        </ul>

        <button onClick={onRestart} style={{ background: theme.accent, color: '#fff', border: 'none', borderRadius: 8, padding: '0.75rem 2rem', fontWeight: 600, marginTop: 16 }}>Restart Quiz</button>
      </motion.div>
    );
  }

  return (
    <motion.div
      className="quiz-board"
      style={{ background: theme.bg, minHeight: '500px', borderRadius: '24px', padding: '2rem', margin: '2rem auto', maxWidth: 400 }}
      initial={{opacity:0, y:30}}
      animate={{opacity:1, y:0}}
      transition={{duration:0.7}}
    >
      <div className="quiz-progress" style={{ marginBottom: '1.5rem' }}>
        <span style={{ color: theme.accent, fontWeight: 600 }}>{current + 1}/{quiz.questions.length}</span>
        <div className="progress-bar-bg">
          <div
            className="progress-bar-fill"
            style={{ width: `${((current + 1) / quiz.questions.length) * 100}%`, background: theme.accent }}
          />
        </div>
        <button className="quiz-exit" onClick={onRestart} title="Exit Quiz">✖</button>
      </div>
      <div className="quiz-avatar" style={{ fontSize: '2.5rem', marginBottom: '1rem' }}>{avatar}</div>
      <h3 style={{ color: '#23254c', textAlign: 'center', marginBottom: '2rem' }}>{q.text}</h3>
      <div className="quiz-options">
        {q.options.map((opt, idx) => (
          <button
            key={idx}
            className={`quiz-option${selected === idx ? ' selected' : ''}`}
            style={{ borderColor: selected === idx ? theme.accent : '#e5e7eb' }}
            onClick={() => handleOption(idx)}
            type="button"
          >
            <span className="quiz-radio" style={{ borderColor: selected === idx ? theme.accent : '#cbd5e1' }}>
              {selected === idx && <span className="quiz-radio-inner" style={{ background: theme.accent }} />}
            </span>
            <span>{opt}</span>
          </button>
        ))}
      </div>
      <button
        className="quiz-next"
        onClick={handleNext}
        disabled={selected === null}
        style={{ background: theme.accent, opacity: selected === null ? 0.5 : 1 }}
      >
        Next
      </button>
    </motion.div>
  );
}

function QuizBuilder() {
  const [quiz, setQuiz] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);

  const handleGenerate = async params => {
    setLoading(true);
    setError(null);
    try {
      const data = await fetchQuiz(params);
      setQuiz(data);
    } catch (err) {
      setError(err.message || 'Failed to generate quiz.');
    } finally {
      setLoading(false);
    }
  };
  const handleRestart = () => setQuiz(null);

  if (loading) return <div style={{textAlign:'center',marginTop:'2rem'}}>Generating quiz...</div>;
  if (error) return <div style={{color:'red',textAlign:'center',marginTop:'2rem'}}>{error}</div>;

  return quiz ? (
    <QuizBoard quiz={quiz} onRestart={handleRestart} />
  ) : (
    <QuizSetup onGenerate={handleGenerate} />
  );
}

export default QuizBuilder;
